import java.io.*;
import java.util.Base64;

public class SecureDeserializationExample {
    public static void main(String[] args) {
        try {
            String serializedObject = "rO0ABXNyABdqYXZhLnV0aWwuRGF0YSRMamF2YS9sYW5nL1N0cmluZzt4cAAAAAAAAAACAAAAAAAAAA";

            byte[] data = Base64.getDecoder().decode(serializedObject);
            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(data));

            // Check if the object being deserialized is of an expected type
            Object obj = ois.readObject();
            if (obj instanceof String) {
                String deserializedString = (String) obj;
                System.out.println("Deserialized object: " + deserializedString);
            } else {
                System.out.println("Unexpected object type during deserialization.");
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Insecure Deserialization
